import xml.etree.ElementTree as ET

def parse_xml_config(config_file):
    tree = ET.parse(config_file)
    root = tree.getroot()
    settings = {}
    for child in root:
        if child.tag == "setting":
            name = child.attrib["name"]
            value = child.text
            settings[name] = value
    return settings
